func TestTruncateBody(t *testing.T) {
	t.Parallel()

	const maxBytes = 4096

	cases := []struct {
		name        string
		input       []byte
		wantLen     int
		wantHasTail bool
	}{
		{"empty", nil, 0, false},
		{"under cap", []byte("hello"), 5, false},
		{"at cap", bytes.Repeat([]byte("a"), maxBytes), maxBytes, false},
		{"one over cap", bytes.Repeat([]byte("a"), maxBytes+1), maxBytes + 3, true},
		{"huge body", bytes.Repeat([]byte("a"), maxBytes*8), maxBytes + 3, true},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			got := truncateBody(tc.input)
			if len(got) != tc.wantLen {
				t.Fatalf("len = %d, want %d", len(got), tc.wantLen)
			}
			if tc.wantHasTail && !strings.HasSuffix(got, "...") {
				t.Fatalf("want trailing %q", "...")
			}
			if !tc.wantHasTail && strings.HasSuffix(got, "...") {
				t.Fatalf("unexpected trailing %q in %q", "...", got)
			}
		})
	}
}

func TestTruncateBody_UTF8RuneAtBoundary(t *testing.T) {
	t.Parallel()

	// '€' is 3 bytes (0xE2 0x82 0xAC). Place it so the slice at byte 4096 cuts
	// mid-rune; strings.ToValidUTF8 should drop the partial rune cleanly rather
	// than emit U+FFFD or invalid UTF-8.
	prefix := strings.Repeat("a", 4094)
	body := []byte(prefix + "€" + strings.Repeat("b", 100))
	got := truncateBody(body)

	if !utf8.ValidString(got) {
		t.Fatalf("output is not valid UTF-8")
	}
	if strings.ContainsRune(got, utf8.RuneError) {
		t.Fatalf("output contains replacement rune U+FFFD")
	}
	if !strings.HasSuffix(got, "...") {
		t.Fatalf("want trailing %q", "...")
	}
	// Partial rune must be dropped, not replaced: 4094 valid bytes + "...".
	if want := 4094 + 3; len(got) != want {
		t.Fatalf("len = %d, want %d (partial rune should be dropped, not replaced)", len(got), want)
	}
}

func TestClientAppliesPaperclipAuthModes(t *testing.T) {
	cases := []struct {
		name              string
		cfg               config.Config
		wantAuthorization string
		wantCookie        string
	}{
		{name: "none", cfg: config.Config{AuthMode: "none"}},
		{name: "board session", cfg: config.Config{AuthMode: "board-session", SessionCookie: "session-secret"}, wantCookie: "paperclip_session=session-secret"},
		{name: "board API key", cfg: config.Config{AuthMode: "board-api-key", BoardAPIKey: "board-secret"}, wantAuthorization: "Bearer board-secret"},
		{name: "agent bearer", cfg: config.Config{AuthMode: "agent-bearer", AgentToken: "agent-secret"}, wantAuthorization: "Bearer agent-secret"},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
				if got := r.Header.Get("Authorization"); got != tc.wantAuthorization {
					t.Errorf("Authorization = %q, want %q", got, tc.wantAuthorization)
				}
				if got := r.Header.Get("Cookie"); got != tc.wantCookie {
					t.Errorf("Cookie = %q, want %q", got, tc.wantCookie)
				}
				w.Header().Set("Content-Type", "application/json")
				_, _ = w.Write([]byte(`{"ok":true}`))
			}))
			t.Cleanup(server.Close)

			tc.cfg.BaseURL = server.URL
			c := New(&tc.cfg, time.Second, 0)
			c.HTTPClient = server.Client()
			c.NoCache = true
			if _, err := c.Get(context.Background(), "/auth-check", nil); err != nil {
				t.Fatalf("Get returned error: %v", err)
			}
		})
	}
}

func TestMutatingRequestsAreNotRetried(t *testing.T) {
	requests := 0
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requests++
		http.Error(w, "temporary", http.StatusInternalServerError)
	}))
	t.Cleanup(server.Close)

	c := New(&config.Config{BaseURL: server.URL}, time.Second, 0)
	c.HTTPClient = server.Client()
	_, _, err := c.Post(context.Background(), "/mutate", map[string]any{"name": "one"})
	if err == nil {
		t.Fatal("Post returned nil error")
	}
	if requests != 1 {
		t.Fatalf("request count = %d, want 1", requests)
	}
}

func TestRedactSensitiveJSONRecurses(t *testing.T) {
	input := map[string]any{
		"name": "visible",
		"credentials": map[string]any{
			"apiKey": "top-secret",
			"nested": []any{map[string]any{"password": "also-secret"}},
		},
	}
	redacted := redactSensitiveJSON(input)
	encoded, err := json.Marshal(redacted)
	if err != nil {
		t.Fatal(err)
	}
	got := string(encoded)
	if strings.Contains(got, "top-secret") || strings.Contains(got, "also-secret") {
		t.Fatalf("redacted JSON leaked credentials: %s", got)
	}
	if !strings.Contains(got, "visible") {
		t.Fatalf("redacted JSON removed non-sensitive value: %s", got)
	}
}

func TestMaskCredentialTextRedactsTokenBearingPaths(t *testing.T) {
	c := &Client{}
	for _, raw := range []string{
		"POST /api/invites/invite-secret/accept returned HTTP 404",
		"GET https://example.test/api/board-claim/claim-secret?mode=one",
	} {
		got := c.maskCredentialText(raw)
		if strings.Contains(got, "invite-secret") || strings.Contains(got, "claim-secret") {
			t.Fatalf("masked diagnostic leaked path credential: %q", got)
		}
		if !strings.Contains(got, "REDACTED") {
			t.Fatalf("masked diagnostic = %q, want redaction marker", got)
		}
	}
}

func TestCacheKeyDelimitsSortedQueryParams(t *testing.T) {
	t.Parallel()

	c := &Client{BaseURL: "https://api.example.test"}
	collidingTwoParams := c.cacheKey("/titles", map[string]string{
		"country": "USAformat",
		"year":    "bluray",
	})
	collidingThreeParams := c.cacheKey("/titles", map[string]string{
		"country": "USA",
		"format":  "bluray",
		"year":    "",
	})
	if collidingTwoParams == collidingThreeParams {
		t.Fatalf("cache keys collided for adjacent query params: %q", collidingTwoParams)
	}

	first := c.cacheKey("/titles", map[string]string{"format": "4k", "country": "USA"})
	second := c.cacheKey("/titles", map[string]string{"country": "USA", "format": "4k"})
	if first != second {
		t.Fatalf("cache key should be deterministic regardless of map order: %q != %q", first, second)
	}
}

func TestGetWithHeadersValuesPreservesRepeatedQueryParams(t *testing.T) {
	t.Parallel()

	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		got := r.URL.Query()["format"]
		if len(got) != 2 || got[0] != "blu-ray" || got[1] != "4k" {
			t.Fatalf("format query values = %#v, want [blu-ray 4k]", got)
		}
		if got := r.URL.Query().Get("country"); got != "US" {
			t.Fatalf("country = %q, want US", got)
		}
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(`{"ok":true}`))
	}))
	t.Cleanup(server.Close)

	c := New(&config.Config{BaseURL: server.URL}, time.Second, 0)
	c.HTTPClient = server.Client()
	c.NoCache = true

	params := url.Values{
		"format":  []string{"blu-ray", "4k"},
		"country": []string{"US"},
	}
	if _, err := c.GetWithHeadersValues(context.Background(), "/titles", params, nil); err != nil {
		t.Fatalf("GetWithHeadersValues returned error: %v", err)
	}
}
